// EP-43: heuristic Sidon pair search with disjoint differences.
{
  const N = 70;
  const rng = makeRng(20260304 ^ 43);

  function buildPair() {
    const A = sidonGreedyRandom(N, 10, rng, 10);
    const diffsA = new Uint8Array(N);
    for (let i = 0; i < A.length; i += 1) {
      for (let j = i + 1; j < A.length; j += 1) diffsA[A[j] - A[i]] = 1;
    }
    const order = Array.from({ length: N }, (_, i) => i + 1);
    shuffle(order, rng);
    const B = [];
    const diffsB = new Uint8Array(N);
    for (const x of order) {
      let ok = true;
      for (const b of B) {
        const d = Math.abs(x - b);
        if (diffsB[d] || diffsA[d]) {
          ok = false;
          break;
        }
      }
      if (!ok) continue;
      for (const b of B) diffsB[Math.abs(x - b)] = 1;
      B.push(x);
    }
    return { A: A.slice().sort((a, b) => a - b), B: B.slice().sort((a, b) => a - b) };
  }

  let best = { score: -1, A: [], B: [] };
  for (let r = 0; r < 120; r += 1) {
    const { A, B } = buildPair();
    const score = (A.length * (A.length - 1)) / 2 + (B.length * (B.length - 1)) / 2;
    if (score > best.score) best = { score, A, B };
  }

  out.results.ep43 = {
    description: 'Heuristic greedy Sidon pair construction with disjoint difference sets.',
    N,
    best_score: best.score,
    size_A: best.A.length,
    size_B: best.B.length,
    A: best.A,
    B: best.B,
  };
}
